(139, '_site_transient_community-events-ac623c97556af98b0c073d91bd271cb2', 'a:4:{s:9:\"sandboxed\";b:0;s:5:\"error\";N;s:8:\"location\";a:1:{s:2:\"ip\";s:13:\"192.168.176.0\";}s:6:\"events\";a:2:{i:0;a:10:{s:4:\"type\";s:8:\"wordcamp\";s:5:\"title\";s:45:\"WordPress and Remote Work (Online) in Spanish\";s:3:\"url\";s:54:\"https://events.wordpress.org/denia/2024/trabajoremoto/\";s:6:\"meetup\";N;s:10:\"meetup_url\";N;s:4:\"date\";s:19:\"2024-10-19 11:00:00\";s:8:\"end_date\";s:19:\"2024-10-19 11:00:00\";s:20:\"start_unix_timestamp\";i:1729328400;s:18:\"end_unix_timestamp\";i:1729328400;s:8:\"location\";a:4:{s:8:\"location\";s:6:\"Online\";s:7:\"country\";s:2:\"ES\";s:8:\"latitude\";d:38.8387992;s:9:\"longitude\";d:0.1050557;}}i:1;a:10:{s:4:\"type\";s:6:\"meetup\";s:5:\"title\";s:18:\"Wordpress & Cañas\";s:3:\"url\";s:65:\"https://www.meetup.com/mallorca-wordpress-meetup/events/303899659\";s:6:\"meetup\";s:18:\"WordPress Mallorca\";s:10:\"meetup_url\";s:49:\"https://www.meetup.com/mallorca-wordpress-meetup/\";s:4:\"date\";s:19:\"2024-11-01 19:00:00\";s:8:\"end_date\";s:19:\"2024-11-01 21:00:00\";s:20:\"start_unix_timestamp\";i:1730484000;s:18:\"end_unix_timestamp\";i:1730491200;s:8:\"location\";a:4:{s:8:\"location\";s:12:\"Palma, Spain\";s:7:\"country\";s:2:\"es\";s:8:\"latitude\";d:39.5696;s:9:\"longitude\";d:2.65016;}}}}', 'off'),
