(141, '_transient_feed_69c933d8a78805efd0abe985766ffb51', 'a:4:{s:5:\"child\";a:1:{s:0:\"\";a:1:{s:3:\"rss\";a:1:{i:0;a:6:{s:4:\"data\";s:3:\"\n\n\n\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:7:\"version\";s:3:\"2.0\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:0:\"\";a:1:{s:7:\"channel\";a:1:{i:0;a:6:{s:4:\"data\";s:52:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\n \n	\n		\n		\n		\n		\n		\n		\n		\n		\n		\n	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:8:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"WordPress.org España\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"https://es.wordpress.org\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Español\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:13:\"lastBuildDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 08 Oct 2024 18:33:43 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"language\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"es\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:9:\"generator\";a:1:{i:0;a:5:{s:4:\"data\";s:40:\"https://wordpress.org/?v=6.7-beta2-59199\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"image\";a:1:{i:0;a:6:{s:4:\"data\";s:11:\"\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:0:\"\";a:5:{s:3:\"url\";a:1:{i:0;a:5:{s:4:\"data\";s:29:\"https://s.w.org/favicon.ico?2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"WordPress.org España\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"https://es.wordpress.org\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"width\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:6:\"height\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}s:4:\"item\";a:10:{i:0;a:6:{s:4:\"data\";s:79:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"WordPress 6.7 Beta 1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://es.wordpress.org/2024/10/05/wordpress-6-7-beta-1/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:65:\"https://es.wordpress.org/2024/10/05/wordpress-6-7-beta-1/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 05 Oct 2024 21:53:31 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.7\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:4:\"beta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=662489\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:362:\"¡WordPress 6.7 Beta 1 ya está aquí! Por favor, descárgalo y pruébalo. Esta versión beta del software WordPress está en desarrollo.&#160;No instales, ejecutes ni pruebes esta versión de WordPress en webs en producción o críticos; si lo haces, corres el riesgo de obtener resultados inesperados. En su lugar, instala la beta 1 en sitios locales [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:14155:\"\n<p>¡WordPress 6.7 Beta 1 ya está aquí! Por favor, descárgalo y pruébalo.</p>\n\n\n\n<p><strong>Esta versión beta del software WordPress está en desarrollo.</strong>&nbsp;No instales, ejecutes ni pruebes esta versión de WordPress en webs en producción o críticos; si lo haces, corres el riesgo de obtener resultados inesperados.</p>\n\n\n\n<p>En su lugar, instala la beta 1 en sitios locales y entornos de prueba de cualquiera de estas cuatro formas:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><th>Plugin</th><td>Instala y activa el plugin&nbsp;<a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\" target=\"_blank\" rel=\"noreferrer noopener\">WordPress Beta Tester</a>&nbsp;en una instalación de WordPress. (Elige el canal «Desarrollo temprano» y la transmisción «Solo Beta/RC»).</td></tr><tr><th>Descarga directa</th><td>Descarga la <a href=\"https://wordpress.org/wordpress-6.7-beta1.zip\" target=\"_blank\" rel=\"noreferrer noopener\">versión Beta 1 (zip)</a> e instálala en una web WordPress.</td></tr><tr><th>Línea de comandos</th><td>Usa el siguiente comando <a href=\"https://make.wordpress.org/cli/\" target=\"_blank\" rel=\"noreferrer noopener\">WP-CLI</a>:<br><code>wp core update --version=6.7-beta1</code></td></tr><tr><th>Zona de pruebas de WordPress</th><td>Usa la <a href=\"https://playground.wordpress.net/#%7B%20%22preferredVersions%22:%20%7B%20%22php%22:%20%228.0%22,%20%22wp%22:%20%22beta%22%20%7D,%20%22features%22:%20%7B%20%22networking%22:%20true%20%7D,%20%22steps%22:%20[%20%7B%20%22step%22:%20%22login%22,%20%22username%22:%20%22admin%22,%20%22password%22:%20%22password%22%20%7D,%20%7B%20%22step%22:%20%22importFile%22,%20%22file%22:%20%7B%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/wpaccessibility/a11y-theme-unit-test/master/a11y-theme-unit-test-data.xml%22%20%7D%20%7D,%20%7B%20%22step%22:%20%22importFile%22,%20%22file%22:%20%7B%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/WordPress/theme-test-data/master/themeunittestdata.wordpress.xml%22%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22query-monitor%22%20%7D,%20%22options%22:%20%7B%20%22activate%22:%20false%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22create-block-theme%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22debug-bar%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22health-check%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22test-reports%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22user-switching%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D%20]%20%7D\" target=\"_blank\" rel=\"noreferrer noopener\">instancia 6.7 Beta 1 en la zona de pruebas de WordPress</a> para probar el software directamente en tu navegador sin tener que hacerlo en un sitio o configuración independiente. </td></tr></tbody></table></figure>\n\n\n\n<p>La fecha prevista actual para el lanzamiento final de WordPress 6.7 es <strong>el 12 de noviembre de 2024</strong> . Tu ayuda probando esta versión es clave para garantizar que todo el contenido de la versión sea estable.</p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué importancia tienen tus pruebas?</h2>\n\n\n\n<p>Hacer pruebas para buscar problemas es una parte crítica del desarrollo de cualquier software, y es un modo significativo con el que cualquier puede contribuir &#8211; tengas on o experiencia.</p>\n\n\n\n<p>Si descubres un problema, por favor, compártelo en el <a href=\"https://wordpress.org/support/forum/alphabeta/\">área Alpha/Beta</a> de los foros de soporte. Si te sientes con comodidad enviando un informe de fallos replicable, puedes hacerlo desde el <a href=\"https://core.trac.wordpress.org/newticket\">trac de WordPress</a>. Tambien puedes comprobar si tu problema está en la lista de <a href=\"https://core.trac.wordpress.org/tickets/major\">fallos conocidos</a>.</p>\n\n\n\n<p>¿Tienes curiosidad sobre cómo probar versiones en general y sobre cómo dar los primeros pasos? No te pierdas las <a href=\"https://make.wordpress.org/test/\">iniciativas de pruebas en Make Core</a> y únete al <a href=\"https://wordpress.slack.com/messages/core-test/\">canal #core-test</a> en el <a href=\"https://wordpress.slack.com/\">Slack de Making WordPress</a>.</p>\n\n\n\n<p>WordPress 6.7 incluirá muchas nuevas características que estaban previamente solo disponibles en el plugin Gutenberg. Aprende más sobre las actualizaciones de Gutenberg desde WordPress 6.7 en las entradas de <a href=\"https://make.wordpress.org/core/tag/gutenberg-new/\">novedades de Gutenberg</a> para las versiones <a href=\"https://make.wordpress.org/core/2024/06/09/what-is-new-in-gutenberg-18-5-05-jun/\">18.5</a>, <a href=\"https://make.wordpress.org/core/2024/06/20/whats-new-in-gutenberg-18-6/\">18.6</a>, <a href=\"https://make.wordpress.org/core/2024/07/04/whats-new-in-gutenberg-18-7-03-july/\">18.7</a>, <a href=\"https://make.wordpress.org/core/2024/07/17/whats-new-in-gutenberg-18-8-17-july/\">18.8</a>, <a href=\"https://make.wordpress.org/core/2024/07/31/whats-new-in-gutenberg-18-9-31-july/\">18.9</a>, <a href=\"https://make.wordpress.org/core/2024/08/14/whats-new-in-gutenberg-19-0-14-august/\">19.0</a>, <a href=\"https://make.wordpress.org/core/2024/08/28/whats-new-in-gutenberg-19-1-28-august/\">19.1</a>, <a href=\"https://make.wordpress.org/core/2024/09/12/what-is-new-in-gutenberg-19-2-11-september/\">19.2</a> y <a href=\"https://make.wordpress.org/core/2024/09/25/whats-new-in-gutenberg-19-3-25-september/\">19.3</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Qué novedades hay en WordPress 6.7 Beta 1</h2>\n\n\n\n<p>WordPress 6.7 Beta 1 contiene más de 500 mejoras y más de 500 correcciones a fallos en del editor, incluidos más de <a href=\"https://core.trac.wordpress.org/query?status=closed&amp;milestone=6.7&amp;group=component&amp;max=500&amp;col=id&amp;col=summary&amp;col=owner&amp;col=type&amp;col=priority&amp;col=component&amp;col=version&amp;order=priority\">200 tiques del núcleo de WordPress 6.7</a>. Aquí tienes un avance de lo que está por venir:</p>\n\n\n\n<h3 class=\"wp-block-heading\">Te presentamos el tema Twenty Twenty-Five</h3>\n\n\n\n<p>El nuevo tema por defecto, <a href=\"https://make.wordpress.org/core/2024/08/15/introducing-twenty-twenty-five/\">Twenty Twenty-Five</a>, se lanzará con WordPress 6.7. </p>\n\n\n\n<p>Encarna la máxima flexibilidad y adaptabilidad, y muestra cómo WordPress te permite contar tu historia con una amplia selección de patrones y estilos. Inspirado en destellos de belleza natural y herencia ancestral, evoca ideas de transietoriedad, el paso del tiempo y la evolución continua, reflejando el viaje de la vida. </p>\n\n\n\n<p>Experimenta la creación de sitios sin esfuerzo con Twenty Twenty-Five y sigue su progreso o informa problemas en <a href=\"https://github.com/wordpress/twentytwentyfive\">este repositorio de GitHub</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Alejarte para crear usando patrones</h3>\n\n\n\n<p>La vista de «Alejar» simplifica la experiencia de edición al permitirte crear y editar a nivel de patrón en lugar de centrarste en bloques individuales.</p>\n\n\n\n<p>Alterna fácilmente esta vista desde la barra de herramientas para agilizar el proceso de creación de tu sitio, lo que hace que sea más rápido e intuitivo diseñar páginas con patrones.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Mejoras en medios </h3>\n\n\n\n<p>Ahora, con compatibilidad con la carga de imágenes HEIC (convertidas automáticamente a JPEG para una máxima compatibilidad), puedes añadir imágenes de alta calidad sin preocuparte por la compatibilidad del navegador. </p>\n\n\n\n<p>Además, disfruta del ajuste automático del tamaño de las imágenes subidas de forma diferida y de opciones de imagen de fondo ampliadas tanto a nivel individual como global, lo que te brinda un mayor control sobre las imágenes y el rendimiento de tu sitio.  </p>\n\n\n\n<h3 class=\"wp-block-heading\">Ampliando la compatibilidad de bloques</h3>\n\n\n\n<p>Ahora varios bloques tienen opciones ampliadas de compatiblidad, permitiendo incluso mayores posibilidades de diseño. Es de destacar que se ha añadido la compatibilidad con bloques de grupos, solicitada hace mucho tiempo, ¡una gran ventaja para diseñadores y desarrolladores de temas!</p>\n\n\n\n<h3 class=\"wp-block-heading\">API de opciones de vista previa </h3>\n\n\n\n<p>La última versión de WordPress mejora las opciones de vista previa en el editor de bloques, lo que permite a los desarrolladores personalizar las vistas previas de contenido. Una nueva API permite que los plugins y temas añadan elementos personalizados al menú desplegable de vista previa, lo que permite a los usuarios ver el contenido en diferentes formatos o entornos. Esta flexibilidad enriquece la experiencia de edición al tiempo que mantiene la estructura familiar existente del menú desplegable de vista previa.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Vistas de datos refinadas</h3>\n\n\n\n<p>Las vistas de datos introducidas en la versión 6.5 siguen mejorando. Esta versión se centra en perfeccionar la experiencia con algunas características nuevas destinadas a hacer que estas vistas sean más flexibles para la personalización y más funcionales para su uso. </p>\n\n\n\n<h3 class=\"wp-block-heading\">Administrar enlaces de bloques directamente</h3>\n\n\n\n<p>Las actualizaciones de esta API en la versión 6.7 pulen y abren la mayoría de las API subyacentes, lo que mejora la experiencia general del usuario y añade una interfaz de usuario (IU) que permite conectar atributos con campos personalizados a sus fuentes de enlace. Esta nueva IU permite crear enlaces directamente en un bloque en lugar de tener que usar el Editor de código. Por defecto, los usuarios administradores y editores pueden crear y modificar enlaces, pero esto se puede anular con los filtros `<code>block_editor_settings_all</code> o <code>map_meta_cap</code>`.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Bloque de consulta de contenidos simplificado e inteligente</h3>\n\n\n\n<p>El bloque de consulta de contenidos se ha mejorado, ya que ahora hereda por defecto automáticamente la consulta de la plantilla, lo que elimina la necesidad de configuración manual. Esto significa que tus entradas se muestran inmediatamente tanto en el editor como en la web, lo que agiliza el proceso para que los usuarios puedan centrarse en el contenido sin necesidad de realizar configuraciones adicionales.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Editar y controlar los ajustes por defecto del tamaño de fuente</h3>\n\n\n\n<p>Una interfaz de estilos mejorada permite una mayor flexibilidad a la hora de crear, editar, eliminar y aplicar ajustes preestablecidos de tamaño de fuente. Ahora puedes modificar fácilmente los ajustes preestablecidos que ofrece un tema o crear tus propias opciones personalizadas. Una característica clave es la capacidad de alternar la tipografía fluida, lo que permite un escalado de fuentes adaptable con opciones adicionales para un control más preciso de la capacidad de respuesta.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Ver los cuadros meta en el editor de entradas en formato iframe</h3>\n\n\n\n<p>Se ha introducido una nueva opción de vista dividida que permite acceder tanto al lienzo del editor como a las cajas meta durante la edición. Este cambio proporcionará una experiencia WYSIWYG consistente entre el editor y las vistas de la interfaz.</p>\n\n\n\n<h3 class=\"wp-block-heading\">API de registro de plantillas</h3>\n\n\n\n<p>Con esta versión, los desarrolladores pueden registrar plantillas de bloques personalizadas con mayor facilidad sin filtros complejos. Agiliza tu proceso de desarrollo y crea plantillas personalizadas con facilidad. </p>\n\n\n\n<p><strong><strong>Las características incluidas en esta primera versión beta pueden cambiar antes del lanzamiento final de WordPress 6.7, en función de lo que encuentren los evaluadores como tú.</strong></strong></p>\n\n\n\n<p>Echa un vistazo al <a href=\"https://make.wordpress.org/core/6-7/\">ciclo de lanzamiento de la versión 6.7</a> y revisa las entradas <a href=\"https://make.wordpress.org/core/tag/6-7/\">relacionadas con la versión 6.7 del blog de Make Core</a> las próximas semanas para tener más detalles.</p>\n\n\n\n<h2 class=\"wp-block-heading\">La recompensa por vulnerabilidad se duplica durante la versión Beta y la versión candidata</h2>\n\n\n\n<p>La comunidad de WordPress patrocina una <a href=\"https://make.wordpress.org/security/2024/02/12/welcoming-2024-with-wordpress-6-5-beta-1/\">recompensa monetaria por informar sobre vulnerabilidades de seguridad nuevas e inéditas</a> . Esta recompensa se duplica durante el período comprendido entre la versión Beta 1, el 1 de octubre de 2024, y la versión final candidata a lanzamiento (RC), programada para el 5 de noviembre de 2024. Sigue las prácticas de divulgación responsable que se detallan en las prácticas y políticas de seguridad del proyecto que se describen en la <a href=\"https://hackerone.com/wordpress\">página de HackerOne</a> y en el <a href=\"https://wordpress.org/about/security/\">informe técnico de seguridad</a> .</p>\n\n\n\n<h3 class=\"wp-block-heading\">Solo para ti: un haiku de la Beta 1</h3>\n\n\n\n<pre class=\"wp-block-verse\">Surgen líneas de código, <br>las pruebas dan forma al camino futuro,  <br>WordPress crece una vez más.</pre>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:62:\"https://es.wordpress.org/2024/10/05/wordpress-6-7-beta-1/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"662489\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:82:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:65:\"Cómo crear una estrategia de marketing de contenidos paso a paso\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:101:\"https://es.wordpress.org/2024/10/03/como-crear-una-estrategia-de-marketing-de-contenidos-paso-a-paso/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:109:\"https://es.wordpress.org/2024/10/03/como-crear-una-estrategia-de-marketing-de-contenidos-paso-a-paso/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 03 Oct 2024 08:40:25 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:4:{i:0;a:5:{s:4:\"data\";s:11:\"copywriting\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:9:\"Marketing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:10:\"Redacción\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:3:\"SEO\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=662123\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:124:\"¿Quieres que tu blog\ndestaque? \n✨ Aprende a crear una estrategia de marketing de\ncontenidos en 8 pasos. \n#ContentMarketin\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"Sofia Ruiz\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5474:\"\n<p>Crear y compartir contenidos <strong>orientados a resolver los problemas y necesidades</strong> de tu<br>potencial cliente te ayudará a destacar en un entorno saturado.</p>\n\n\n\n<p>En este artículo, te contaremos cómo crear una estrategia de marketing de contenidos efectiva, para que siempre estés en el “top of mind”.</p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué es el marketing de contenidos?</h2>\n\n\n\n<p>El marketing de contenidos es una rama del marketing digital que se centra en la <strong>creación y distribución de contenido relevante y valioso</strong> para una audiencia determinada.</p>\n\n\n\n<p>Pero, ¿qué es un contenido relevante y valioso?<br>Nos referimos a un <strong>contenido de carácter educativo que tiene una utilidad real</strong> para el usuario, es decir, que lo ayuda a resolver alguna inquietud.</p>\n\n\n\n<p>Este enfoque no solo contribuye a construir relaciones con los clientes potenciales, sino que también da lugar a beneficios adicionales como:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>mejor posicionamiento en buscadores.</li>\n\n\n\n<li>crecimiento del tráfico orgánico.</li>\n\n\n\n<li>aumento del reconocimiento de tu marca.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">8 pasos para crear una estrategia de marketing de contenidos</h2>\n\n\n\n<p>A continuación, te explicamos cómo crear una estrategia de marketing de contenidos desde cero.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Definir tus objetivos</h3>\n\n\n\n<p>El primer paso es preguntarte: ¿qué quieres lograr con tu estrategia de contenidos?<br>Define tus objetivos para que sean <strong>específicos, medibles, alcanzables, relevantes y puedan alcanzarse</strong> en un tiempo determinado.</p>\n\n\n\n<p>Además, acompáñalos con los indicadores claves de rendimiento (KPIs) adecuados para medir su cumplimiento y ajustar tu estrategia según los resultados obtenidos.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Crear tu buyer persona</h3>\n\n\n\n<p>Para crear contenido que sea valioso para tu audiencia, primero necesitas conocerla.</p>\n\n\n\n<p>Por ello, comienza definiendo a tu buyer persona: una <strong>representación semi-ficticia de tu cliente ideal</strong>, que define aspectos como sus intereses, problemas y motivaciones.</p>\n\n\n\n<p>Hacerlo de este modo te permitirá no solo crear contenido relevante, sino también <a href=\"https://es.wordpress.org/2023/12/14/copywriting-adaptado-a-diferentes-tipos-de-paginas-en-wordpress-blog-y-landing-page/\">adaptar el tono y estilo</a> de escritura según el tipo de página que utilices.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Identificar el recorrido de compra de tu potencial cliente</h3>\n\n\n\n<p>El recorrido de compra que atraviesa un potencial cliente está compuesto por varias etapas (conocimiento, consideración y decisión) y, en cada una de ellas, el usuario tiene diferentes necesidades de información.</p>\n\n\n\n<p>Identifica <strong>qué contenido es necesario crear y poner a disposición en cada fase</strong> para que el cliente potencial pueda resolver sus dudas y avanzar en el embudo.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Auditar el contenido existente</h3>\n\n\n\n<p>Antes de crear nuevo contenido, revisa lo que ya tienes.</p>\n\n\n\n<p>Audita tu sitio web, tu blog, tus redes sociales… ¡todo!, y <strong>clasifica cada pieza</strong> según el tipo de contenido, formato, tema y fase del proceso de compra en que se encuentra.</p>\n\n\n\n<p>Esto te permitirá identificar qué contenido puede ser reutilizado, actualizado o eliminado.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Crear un mapa de contenidos</h3>\n\n\n\n<p>Un mapa de contenidos es un plan detallado que identifica el contenido a crear para cada fase del embudo de compra.</p>\n\n\n\n<p>En él, <strong>debes identificar el punto de dolor de tu buyer persona</strong>, las distintas fases del embudo, las palabras clave que mejor se ajusten y el contenido a compartir. ¡Recuerda incluir el contenido que identificaste en tu auditoría!</p>\n\n\n\n<h3 class=\"wp-block-heading\">Crear un calendario editorial</h3>\n\n\n\n<p>Contar con un calendario editorial <strong>te ayudará a planificar</strong> la frecuencia de publicación y asignar las tareas de creación, revisión y distribución, garantizando siempre la coherencia y la <a href=\"https://es.wordpress.org/2023/11/09/asi-de-facil-puedes-mejorar-la-legibilidad-con-wordpress/\">legibilidad del contenido</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Difundir tu contenido</h3>\n\n\n\n<p>Crear contenido es solo la mitad del trabajo, debes asegurarte de que llegue a tu audiencia.</p>\n\n\n\n<p>Además de optimizar tu contenido para el posicionamiento orgánico en buscadores (SEO), distribúyelo en redes sociales, envíalo a tu lista de correo y utiliza otros canales como guest blogging para darlo a conocer y maximizar su impacto.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Medir y analizar resultados</h3>\n\n\n\n<p>¡Y llegamos al final! ¿O es aquí donde empieza la chicha?</p>\n\n\n\n<p>En una estrategia de marketing de contenidos, algunas métricas clave que puedes monitorear son el tráfico, el tiempo de permanencia en las páginas web, la tasa de rebote, y las conversiones.</p>\n\n\n\n<p>Interpreta esta información para identificar qué está funcionando y qué no, y ajusta tu estrategia. <strong>La mejora continua es clave</strong>.</p>\n\n\n\n<p>Crear contenido útil y enfocado en las necesidades de tu audiencia te ayudará a posicionar tu marca como una referente en el sector, atraer más tráfico a tu sitio web y mejorar la conversión de clientes.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:106:\"https://es.wordpress.org/2024/10/03/como-crear-una-estrategia-de-marketing-de-contenidos-paso-a-paso/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"662123\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"Compartir entradas en borrador con colaboradores externos (con y sin plugin)\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:87:\"https://es.wordpress.org/2024/09/24/compartir-entradas-borrador-colaboradores-externos/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:95:\"https://es.wordpress.org/2024/09/24/compartir-entradas-borrador-colaboradores-externos/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 24 Sep 2024 09:50:26 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:7:\"Código\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:7:\"Plugins\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=630565\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:304:\"Solo hay 2 tipos de usuarios en WordPress. Los que alguna vez han tenido que compartir un borrador con alguien externo a la web, y los que necesitarán hacerlo. Seas del grupo que seas, guarda este artículo en tus marcadores, porque cuando te vuelva a pasar o te pase por primera vez, lo vas a [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"John Mejías\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:11787:\"\n<p><br><em>Solo hay 2 tipos de usuarios en WordPress. Los que alguna vez han tenido que compartir un borrador con alguien externo a la web, y los que necesitarán hacerlo. </em></p>\n\n\n\n<p>Seas del grupo que seas, guarda este artículo en tus marcadores, porque cuando te vuelva a pasar o te pase por primera vez, lo vas a echar de menos.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Introducción</h2>\n\n\n\n<p>Existen muchos casos en los que necesitas que alguien que no tiene acceso a tu WordPress, revise un contenido para dar el visto bueno antes de que lo publiques.</p>\n\n\n\n<p>Si un cliente te ha contratado una publicación, querrá verla antes de hacerla visible para todo el mundo.</p>\n\n\n\n<p>Si tienes colaboradores externos que te ayudan con la edición del contenido, querrán verlo antes.</p>\n\n\n\n<p>Si un autor invitado te envía un artículo y tuviste que ajustar alguna parte del texto, querrá ver los cambios antes.</p>\n\n\n\n<p>La buena noticia es que existen 2 formas de hacerlo muy sencillas. Una a través del plugin <a href=\"https://wordpress.org/plugins/public-post-preview/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Public Post Preview</a> (he usado este de ejemplo, pero <strong>puedes utilizar el que más te convenga</strong>). Y otra introduciendo un código en el archivo functions.php.</p>\n\n\n\n<p>La única mala noticia es no haber leído este artículo antes.</p>\n\n\n\n<h2 class=\"wp-block-heading\">1. Compartir entradas en borrador con un plugin</h2>\n\n\n\n<p>Si no tienes un conocimiento avanzado de WordPress o no tienes acceso al servidor a través de FTP, SFTP, SCP, SSH o del panel de tu hosting, instalar este plugin resolverá rápidamente el problema sin quebraderos de cabeza.</p>\n\n\n\n<p><img src=\"https://s.w.org/images/core/emoji/15.0.3/72x72/26a0.png\" alt=\"⚠\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Antes de hacer nada, haz una copia de seguridad completa de la web. De hecho, lo ideal, si tienes la oportunidad, es <strong>probar el funcionamiento de cualquier plugin en una instalación de WordPress que uses de laboratorio</strong>. Sobre todo para asegurarte de que funciona como esperas y de que cumple con tus expectativas, y no deja restos en la base de datos de tu proyecto principal si decides desinstalarlo.</p>\n\n\n\n<ol class=\"wp-block-list\">\n<li>Busca el complemento en la página de plugins de WordPress, instálalo y actívalo.</li>\n</ol>\n\n\n\n<figure class=\"wp-block-image aligncenter size-full\"><img fetchpriority=\"high\" decoding=\"async\" width=\"389\" height=\"261\" src=\"https://es.wordpress.org/files/2024/07/public-post-preview.png\" alt=\"Plugin de WordPress Public Post Preview\" class=\"wp-image-648684\" srcset=\"https://es.wordpress.org/files/2024/07/public-post-preview.png 389w, https://es.wordpress.org/files/2024/07/public-post-preview-300x201.png 300w\" sizes=\"(max-width: 389px) 100vw, 389px\" /></figure>\n\n\n\n<ol start=\"2\" class=\"wp-block-list\">\n<li>Ve a la sección de entradas, localiza el artículo en borrador que quieres compartir y edítalo. Verás que, justo debajo del desplegable para seleccionar al autor, en el menú vertical derecho, aparece una casilla en blanco con el texto “Activar la vista previa pública”.</li>\n</ol>\n\n\n\n<figure class=\"wp-block-image aligncenter size-full\"><img decoding=\"async\" width=\"276\" height=\"603\" src=\"https://es.wordpress.org/files/2024/07/public-post-preview-activar-vista-previa.png\" alt=\"Funcionalidad de activar la vista previa pública del plugin de WordPress Public Post Preview\" class=\"wp-image-648685\" srcset=\"https://es.wordpress.org/files/2024/07/public-post-preview-activar-vista-previa.png 276w, https://es.wordpress.org/files/2024/07/public-post-preview-activar-vista-previa-137x300.png 137w\" sizes=\"(max-width: 276px) 100vw, 276px\" /></figure>\n\n\n\n<p>Al activar la casilla, justo debajo, aparece un nuevo campo con una URL y un botón de copiar. Esa es la URL que debes copiar y entregar a la persona que necesita ver el texto sin tener que tener una cuenta de usuario.</p>\n\n\n\n<figure class=\"wp-block-image aligncenter size-full\"><img decoding=\"async\" width=\"270\" height=\"687\" src=\"https://es.wordpress.org/files/2024/07/public-post-preview-url-vista-previa.png\" alt=\"Funcionalidad de copiar y compartir la URL de la vista previa del plugin de WordPress Public Post Preview\" class=\"wp-image-648686\" srcset=\"https://es.wordpress.org/files/2024/07/public-post-preview-url-vista-previa.png 270w, https://es.wordpress.org/files/2024/07/public-post-preview-url-vista-previa-118x300.png 118w\" sizes=\"(max-width: 270px) 100vw, 270px\" /></figure>\n\n\n\n<ol start=\"3\" class=\"wp-block-list\">\n<li>Activa la casilla, copia la URL, guarda los cambios y siéntate a espera los halagos (o los reproches) de la persona que tiene que corregir o validar tu artículo. Así de fácil.</li>\n</ol>\n\n\n\n<h2 class=\"wp-block-heading\">2. Compartir entradas en borrador sin plugin</h2>\n\n\n\n<p>Si tu experiencia con WordPress es dilatada, quizás prefieras ahorrarte la instalación de un plugin y conseguir el mismo objetivo añadiendo un código en el archivo functions.php que se encuentra en la carpeta del tema que tienes instalado.</p>\n\n\n\n<p>Para hacer esto, necesitas acceso a las carpetas del servidor a través de una conexión FTP, SFTP, SCP o SSH, y hacer las cosas con mucho cuidado, ya que un error en los archivos del servidor puede acabar con tu web y con tus ilusiones.</p>\n\n\n\n<p><img src=\"https://s.w.org/images/core/emoji/15.0.3/72x72/26a0.png\" alt=\"⚠\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Sepas o no dónde te estás metiendo, antes de nada, <strong>haz una copia de seguridad</strong> completa de la web y, si tienes la oportunidad, realiza los pasos de este punto en un WordPress de prueba hasta comprobar que todo funciona correctamente.</p>\n\n\n\n<ol class=\"wp-block-list\">\n<li>Una vez en el servidor, accede a la carpeta de la versión child de tu tema y haz una copia de seguridad del archivo functions.php:</li>\n</ol>\n\n\n\n<p>El archivo se encuentra en la siguiente ruta:</p>\n\n\n\n<pre class=\"wp-block-code has-white-color has-charcoal-0-background-color has-text-color has-background has-link-color wp-elements-2372d33cd3bd4c758a302f3cedd13724\"><code>/wp-content/themes/nombre-de-tu-tema-child/functions.php</code></pre>\n\n\n\n<p><img src=\"https://s.w.org/images/core/emoji/15.0.3/72x72/2139.png\" alt=\"ℹ\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Si no tiene una carpeta con el nombre de tu tema seguido de “-child”, puedes trabajar de forma temporal con el archivo functions.php que está en la carpeta de tu tema.</p>\n\n\n\n<p>No olvides <strong>crear una versión child de tu tema lo antes posible</strong>, ya que si no todos los cambios que hagas serán sobrescritos la próxima vez que actualices el tema.</p>\n\n\n\n<p>Consulta la documentación de tu tema para más información.</p>\n\n\n\n<ol start=\"2\" class=\"wp-block-list\">\n<li>Abre el archivo con un editor de texto, sitúate el final del texto e introduce el siguiente fragmento de código:</li>\n</ol>\n\n\n\n<pre class=\"wp-block-code has-white-color has-charcoal-0-background-color has-text-color has-background has-link-color wp-elements-7eb68415a538a5a7ae794c42579e0321\"><code>/*\n * Función para compartir borradores con colaboradores externos.\n */\nfunction allow_draft_preview( $query ) {\n    if ( isset( $_GET&#091;\'key\'] ) &amp;&amp; \'guest\' === $_GET&#091;\'key\'] ) {\n        if ( $query-&gt;is_main_query() ) {\n            $query-&gt;set( \'post_status\', array( \'publish\', \'draft\' ) );\n        }\n    }\n}\nadd_action( \'pre_get_posts\', \'allow_draft_preview\' );</code></pre>\n\n\n\n<ol start=\"3\" class=\"wp-block-list\">\n<li>Guarda el archivo, ciérralo y visita la web para confirmar que todo está en orden. Si el código introducido no es el correcto, o ha habido algún error al incorporarlo, tu web dejará de funcionar y aparecerá el siguiente error:</li>\n</ol>\n\n\n\n<figure class=\"wp-block-image aligncenter size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"602\" height=\"122\" src=\"https://es.wordpress.org/files/2024/07/wordpress-error-critico.png\" alt=\"Mensaje de error crítico en la web de WordPress\" class=\"wp-image-648687\" srcset=\"https://es.wordpress.org/files/2024/07/wordpress-error-critico.png 602w, https://es.wordpress.org/files/2024/07/wordpress-error-critico-300x61.png 300w\" sizes=\"auto, (max-width: 602px) 100vw, 602px\" /></figure>\n\n\n\n<ol start=\"4\" class=\"wp-block-list\">\n<li>Revisa el código introducido en functions.php para detectar el problema y, si no lo consigues, restaura la copia del archivo y vuelva a empezar.</li>\n</ol>\n\n\n\n<ol start=\"5\" class=\"wp-block-list\">\n<li>Ve a la sección de entradas, localiza el borrador que quieres compartir, edítalo y, en el menú horizontal pulsa sobre “Ver la entrada” para ver la vista previa de la entrada en borradores.</li>\n</ol>\n\n\n\n<ol start=\"6\" class=\"wp-block-list\">\n<li>Copia la URL de la vista previa y añade al final el código “&amp;key=guest”. Ahora cualquiera con esa URL puede ver el artículo sin necesidad de estar logado ni de tener una cuenta de usuario. La URL final debe ser como la siguiente:</li>\n</ol>\n\n\n\n<pre class=\"wp-block-code has-white-color has-charcoal-0-background-color has-text-color has-background has-link-color wp-elements-cb268c4e0c89e8e2d2bd007295b1fd4e\"><code>https:&#047;&#047;midominio.com/?p=4285&amp;amp;key=guest</code></pre>\n\n\n\n<h2 class=\"wp-block-heading\">3. ¿Cuál es la mejor opción?</h2>\n\n\n\n<p>Incluso en el hipotético caso de que sepas resolver el problema de las 2 formas, la respuesta dependerá de tus necesidades.</p>\n\n\n\n<p>Si no te importa añadir plugins a tu WordPress, tiene ciertas ventajas.</p>\n\n\n\n<p>Con ese plugin puedes activar la vista previa pública solo en los contenidos concretos que quieres compartir, mientras que el fragmento de código del functions.php habilita la vista pública en todas las entradas en borradores, de tal forma que, si alguien conoce el ID de alguna de ellas, podrá acceder al contenido sin tener permisos de usuario.</p>\n\n\n\n<p>Esto es poco probable, pero posible.</p>\n\n\n\n<p>Además, con el plugin, en cualquier momento puedes deshabilitar la vista pública de cualquier contenido con un solo clic.</p>\n\n\n\n<p>A los que nos gusta tener el mínimo de plugins posible para optimizar el rendimiento, la seguridad y el mantenimiento, preferimos añadir código al functions.php, aunque tengamos que habilitar y deshabilitar el fragmento cuando queramos compartir algún borrador.</p>\n\n\n\n<p>Si tienes un archivo functions.php con mucho código, siempre puede crear plugins de forma sencilla con él, siguiendo <a href=\"https://es.wordpress.org/2024/04/25/crear-plugin-cuando-functions-php-se-hace-demasiado-grande/\" target=\"_blank\" rel=\"noreferrer noopener\">esta guía</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">4. Cosas que ya no tienes que (ni debes) hacer</h2>\n\n\n\n<p>Ya no necesitas crear un usuario nuevo para cada cliente o colaborador que necesite validar un artículo, aumentando el número de páginas de autor vacías, las cuales se indexan en Google, derrochan tu crawl budget y aumentan el riesgo de intrusión.</p>\n\n\n\n<p>Por otro lado, ya no necesitas hacer públicos contenidos que son privados o que no están terminados, solo para que alguien externo a la web pueda verlos y dar el visto bueno.</p>\n\n\n\n<p>Estos contenidos también se indexan y aparecen en el buscador, por lo que pueden ser vistos por muchas más personas de las que te gustaría.</p>\n\n\n\n<p>Con WordPress nunca hay una única respuesta correcta y no suele haber una limitación que dure mucho.</p>\n\n\n\n<p>Te invitamos a participar en la gran comunidad de voluntarios y colaboradores de WordPress España para compartir tus conocimientos y establecer sinergias.</p>\n\n\n\n<p>Tu experiencia es la solución a los problemas de otros.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:92:\"https://es.wordpress.org/2024/09/24/compartir-entradas-borrador-colaboradores-externos/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"630565\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"WordPress Diversity Day 2024: Celebrando la Inclusión en la Web\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:99:\"https://es.wordpress.org/2024/09/19/wordpress-diversity-day-2024-celebrando-la-inclusion-en-la-web/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:107:\"https://es.wordpress.org/2024/09/19/wordpress-diversity-day-2024-celebrando-la-inclusion-en-la-web/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 19 Sep 2024 08:37:06 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:13:\"Accesibilidad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:9:\"Comunidad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=662005\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:148:\" ¡No te pierdas WordPress Diversity Day 2024!\n\nEl 28/09 en Valencia, creamos un WordPress más inclusivo.\n\nÚnete por una web accesible para todos.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"lualvarimp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6614:\"\n<h2 class=\"wp-block-heading\">¿Habéis oído hablar de WordPress Diversity Day?</h2>\n\n\n\n<p>Si la respuesta es afirmativa ya sabréis todo lo bueno que va a aportar y, si la respuesta es negativa, dejadme que os explique los motivos por los que considero este evento tan emocionante e importante para la comunidad WordPress.</p>\n\n\n\n<p>Pero lo primero es lo primero: ¿Dónde y cuándo?&#8230; El WordPress Diversity Day se celebrará el<strong> sábado 28 de septiembre en la Sala Cinema de Wayco Ruzafa de Valencia</strong>,</p>\n\n\n\n<p><a href=\"https://events.wordpress.org/valencia/2024/diversityday/tickets/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué es esto de WordPress Diversity Day?</h2>\n\n\n\n<p>El WordPress Diversity Day 2024 será el <strong>segundo evento global</strong> <strong>dedicado a la diversidad y la inclusión</strong> de la comunidad WordPress, el primero fue en Barcelona.</p>\n\n\n\n<p>¿Y esto qué significa?</p>\n\n\n\n<p>Que este evento no es como cualquier otro típico evento de WordPress.</p>\n\n\n\n<p>Imaginad un día entero dedicado a hacer que WordPress (y por extensión, toda la web) sea un entorno más acogedor, en el que se celebre la diversidad dentro de la comunidad y en el que se fomente una <strong>cultura de inclusión, respeto e igualdad</strong> de oportunidades para toda la gente.</p>\n\n\n\n<p>Esa es la esencia del WordPress Diversity Day 2024.</p>\n\n\n\n<p><a href=\"https://events.wordpress.org/valencia/2024/diversityday/tickets/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<p>Este evento es toda una declaración de intenciones, una celebración donde la diversidad es la norma y una llamada a la acción para, a través de la inclusión como motor de innovación, hacer que internet sea <strong>accesible y diverso para todas las personas</strong>.</p>\n\n\n\n<p>Y para lograrlo, en este evento se reunirán más de 80 mentes brillantes, creativas y diversas, es decir, la mejor selección de profesionales que compartirá con nosotros sus conocimientos, experiencias y estrategias para hacer que WordPress sea verdaderamente accesible y represente a todas las voces.</p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Por qué es tan importante el WordPress Diversity Day?</h2>\n\n\n\n<p>¿Os habéis parado a pensar alguna vez en que más de un tercio de las páginas web están realizadas con WordPress?&nbsp;</p>\n\n\n\n<p>Si se consigue hacer un <strong>WordPress más inclusivo</strong>, se estará dando un gran paso hacia un Internet que represente y sirva mejor a todas las personas, independientemente de su origen, capacidades, cultura o identidad de cualquier tipo.</p>\n\n\n\n<p>Esto, además, propiciaría un movimiento inicial que, a su vez, ejercería un efecto dominó sobre el resto de Internet.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Un futuro WordPress más diverso e inclusivo</h2>\n\n\n\n<p>WordPress Diversity Day 2024 no pretende ser un evento aislado, sino el <strong>comienzo de un movimiento</strong> más amplio hacia un ecosistema digital más inclusivo.</p>\n\n\n\n<p>¿Os imagináis un día en el que la comunidad WordPress logre todos estos objetivos? (y otros que se me escapan):</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Temas de WordPress accesibles por defecto (que hasta nuestra abuela podría usar sin problema).</li>\n\n\n\n<li>Plugins que consideren automáticamente la internacionalización y la localización (porque hay vida más allá del inglés).</li>\n\n\n\n<li>Herramientas de creación de contenido promoviendo de forma activa el uso del lenguaje inclusivo (y que escribir de este modo sea tan natural como respirar).</li>\n\n\n\n<li>Una usabilidad que permita la navegación intuitiva (y en la que no haya que ser un genio aeronáutico para entender el funcionamiento de una página web).</li>\n\n\n\n<li>Imágenes y vídeos en los que no sólo aparezca gente guapa y delgada (y así podrá salir mi cara y mi barriga en más de alguna página).</li>\n</ul>\n\n\n\n<p><a href=\"https://events.wordpress.org/valencia/2024/diversityday/tickets/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<p>Ese día llegará pronto pues, gracias a eventos como WordPress Diversity Day 2024, se están dando los pasos necesarios para generar este movimiento en el que transformar la comunidad WordPress, haciendo de ella un <strong>modelo de inclusión a seguir</strong> por otras comunidades tecnológicas.</p>\n\n\n\n<p>Y, si nos lo proponemos, esto no será ciencia ficción, ¡será el futuro a construir!</p>\n\n\n\n<h2 class=\"wp-block-heading\">Aprende, evoluciona, crece</h2>\n\n\n\n<p>¿Qué más os puedo decir para que me hagáis caso y no os perdáis este evento que se celebrará el <strong>sábado 28 de septiembre en la Sala Cinema de Wayco Ruzafa de Valencia</strong>? Pues, así de primeras..</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Ampliaréis vuestra perspectiva al escuchar otras experiencias, comprendiendo de forma más profunda cómo diferentes personas interactúan con la tecnología.</li>\n\n\n\n<li>Desarrollaréis la empatía, aprendiendo a poneros en el lugar de otra gente con diferentes necesidades.</li>\n\n\n\n<li>Mejoraréis vuestras habilidades, adquiriendo conocimientos sobre accesibilidad, diseño y otras prácticas inclusivas que son cada vez más demandadas en la industria.</li>\n</ul>\n\n\n\n<p>Y, aunque el evento dure solo un día, la idea es llevarnos a casa este espíritu y aplicarlo en nuestro día a día con WordPress, ya sea haciendo un plugin, un tema o, simplemente, escribiendo en el blog&#8230;</p>\n\n\n\n<p>Porque siempre podrás hacer algo para que ese pequeño trocito de Internet en el que trabajas sea más acogedor.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Me encanta WordPress</h2>\n\n\n\n<p>Y es que esto es lo mejor que tiene WordPress: Cualquiera puede poner su granito de arena para hacer la web más inclusiva.</p>\n\n\n\n<p>Da igual si alguien es un crack de la programación o si apenas sabe cambiar el color de fondo de su blog.&nbsp;</p>\n\n\n\n<p>Cada cosa cuenta (es como el reciclaje: si cada uno pone de su parte, al final se nota un montón).</p>\n\n\n\n<p>Así que ya lo sabéis, pinchad en <a href=\"https://events.wordpress.org/valencia/2024/diversityday/\">este enlace</a> y participad de forma activa en este evento, porque no podéis olvidaros que la web debería ser un espacio para todas y todos, y que está en nuestras manos hacerlo realidad, comprometiéndonos a llevar los principios de diversidad e inclusión a nuestro trabajo diario con WordPress.</p>\n\n\n\n<p>¡El futuro de WordPress es diverso e inclusivo!</p>\n\n\n\n<p>¡Y comienza en cada uno de nosotros!</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:104:\"https://es.wordpress.org/2024/09/19/wordpress-diversity-day-2024-celebrando-la-inclusion-en-la-web/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"662005\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:55:\"Vuelta al (cole) WordCamp 2024: Ponte guapa, Pontevedra\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"https://es.wordpress.org/2024/09/13/vuelta-al-cole-wordcamp-2024-ponte-guapa-pontevedra/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:96:\"https://es.wordpress.org/2024/09/13/vuelta-al-cole-wordcamp-2024-ponte-guapa-pontevedra/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 13 Sep 2024 10:36:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:9:\"Comunidad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=655334\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:203:\"Volvemos a la vida rutinaria porque se han acabado las vacaciones. Pero no todo es tan malo... hay algo muy bueno que nos espera a finales de la tercera semana de septiembre.\n\n¡WordCamp Pontevedra 2024!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"lualvarimp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7473:\"\n<p>Lo siento mucho&#8230; Volvemos a la vida rutinaria porque se han acabado las vacaciones de verano, las cervecitas al lado de la playa y la desconexión total, dando largos paseos por el pueblo de nuestros abuelos.</p>\n\n\n\n<p>Lo siento de corazón&#8230; Ha llegado septiembre y, con él, las tan esperadas y absurdas colecciones que ocuparán parte de nuestro tiempo y dinero durante varios meses, montando, pieza a pieza, superhéroes de cómic de brillante armadura, esqueletos plastificados de ojos saltones (con sonido incluído) o réplicas de coches de una saga cinematográfica que ya no sabe qué inventar para seguir sacando una nueva entrega cada dos o tres años.</p>\n\n\n\n<p>Y eso que omito otras muchas situaciones que podrían hacernos brotar del interior la tan temida depresión post-vacacional.</p>\n\n\n\n<p>Pero no todo es tan malo&#8230; ¡Qué demonios!&#8230; ¡Hay algo muy bueno que nos espera a finales de la tercera semana de septiembre!</p>\n\n\n\n<p>¡Podremos asistir a nuestra primera WordCamp post-vacacional!</p>\n\n\n\n<h2 class=\"wp-block-heading\">PonteWordCamp, una WordCamp con experiencia</h2>\n\n\n\n<p>La <strong>WordCamp Pontevedra 2024</strong> tendrá lugar los días <strong>20, 21 y 22 de septiembre</strong> y la gente encargada de su organización nos va a brindar un comienzo de temporada espectacular, tanto por ser unos auténticos profesionales, como por llevar a sus espaldas una experiencia previa de cuatro años, realizando estos <strong>eventos de WordPress</strong> que tanto nos gustan.</p>\n\n\n\n<p>Los actos se celebrarán en la <strong>Facultad de Comunicación, en el Campus de Pontevedra de la Universidad de Vigo</strong> y (¡atención, padres!) contará con ludoteca, así que, si alguien quiere acudir a la <strong>WordCamp Pontevedra</strong>, pero no sabe con quién dejar a los hijos, que se despreocupe de ese tema.</p>\n\n\n\n<p>Los niños estarán perfectamente atendidos y los adultos podrán asistir a las ponencias, a las actividades, compartir experiencias con otros profesionales y, sobre todo&#8230;</p>\n\n\n\n<h2 class=\"wp-block-heading\">Comer pulpo</h2>\n\n\n\n<p>Porque no hay mejor pulpo para llevarse a la boca que aquel que se prepara en Galicia (esto es una verdad como un templo de grande).</p>\n\n\n\n<p>La gastronomía gallega es algo espectacular y, en esta <strong>WordCamp Pontevedra 2024</strong>, los organizadores no van a privarnos de probar su suculenta cocina.</p>\n\n\n\n<p>Puede que esta afirmación que hago sobre la comida pueda parecer algo superficial pero, en verdad, es algo importante, ya que los mejores sitios para entablar relaciones, hacer negocios y cerrar tratos son aquellos en los que la persona se siente a gusto y satisfecha, al encontrarse en un ambiente distendido y, además, si ha comido bien y se ha llenado la panza, mucho mejor.</p>\n\n\n\n<p>Este concepto de los negocios es algo que tienen muy claro en esta quinta edición de la <strong>WordCamp Pontevedra 2024</strong> y por eso, este evento de <strong>WordPress</strong> de los días <strong>20, 21 y 22 de septiembre</strong>, girará en torno a&#8230;</p>\n\n\n\n<h2 class=\"wp-block-heading\">Emprender con WordPress</h2>\n\n\n\n<p>Esta WordCamp abordará, con sus ponencias y actividades, la temática del uso de WordPress como una herramienta imprescindible para el emprendimiento de cualquier proyecto.</p>\n\n\n\n<p>Para ello, el <strong>20 de septiembre</strong>, ofertarán dos actividades diferenciadas, gratuitas e independientes de la <strong>WordCamp Pontevedra 2024</strong>. Ese día podrán reunirse tanto los que acaban de descubrir la aplicación, como los usuarios habituales del programa o los profesionales de <strong>WordPress</strong> para, así, crear un grupo en el que cualquiera de los interesados pueda formar parte de esta <strong>Comunidad de WordPress</strong>, que cada día crece más.</p>\n\n\n\n<p>Las dos actividades que se realizarán: un <strong>taller de iniciación</strong> y un <strong>do_action hackaton</strong> (un evento en el que, en ese mismo día, se planifican y crean sitios web para organizaciones sin ánimo de lucro del ámbito local) serán los encargados de dar este pistoletazo de salida a la <strong>WordCamp Pontevedra 2024</strong>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Una WordCamp más dinámica y práctica</h2>\n\n\n\n<p>El <strong>21 de septiembre</strong> tendrá lugar la <strong>WordCamp</strong> propiamente dicha (<strong>PonteWordCamp</strong> para los amigos), orientada principalmente a la participación de los asistentes, a través de una serie de formatos más prácticos y dinámicos.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Charlas largas, de 20 minutos, con preguntas de los asistentes al final de la misma para profundizar en el tema.</li>\n\n\n\n<li>Charlas cortas, de 10 minutos, y sin preguntas, en las que el ponente será conciso y resaltará los puntos claves del tema.</li>\n\n\n\n<li>Talleres, de 60 minutos, para aprender a través de la práctica, gracias a la guía de un profesional.</li>\n\n\n\n<li>Demo, de 10 minutos, para aprender los conceptos y el funcionamiento de una aplicación o un plugin.</li>\n\n\n\n<li>Auditoría, de 20 minutos, en el que se revisará un proyecto real, mostrando las áreas buenas y las mejorables de dicho proyecto.</li>\n\n\n\n<li>Consultoría, de 10 minutos, en los que se darán consejos y recomendaciones personalizadas a las dudas y problemas de los asistentes.</li>\n\n\n\n<li>Debate abierto, de 60 minutos, en los que se entablará una conversación abierta y dinámica sobre un tema relevante de WordPress y el emprendimiento.</li>\n</ul>\n\n\n\n<p>¡Y cómo no!&#8230; Toda esta genial serie de formatos vendrá acompañada, en los pertinentes descansos, de buena compañía, buena comida&#8230;</p>\n\n\n\n<p>¡Y pulpo! (como no lo haya, sé de unos cuantos que van a poner precio a mi cabeza)</p>\n\n\n\n<p>A las 19:30 del 21 de septiembre empezará el After Party, el momento perfecto para que surjan todas esas buenas charlas pendientes entre los asistentes y para que empiecen a germinar esas semillas del emprendimiento y los negocios, plantadas desde el primer día por la gente encargada de la organización de la <strong>WordCamp Pontevedra 2024</strong>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">El colofón final</h2>\n\n\n\n<p>El <strong>22 de septiembre</strong> tendrá lugar el <strong>Día de la Comunidad</strong>, un momento perfecto para, si aún no lo eres, formar parte de esta gran <strong>Comunidad de WordPress</strong> y contribuir con el conocimiento que poseas, porque, hasta el más pequeño de tus conocimientos, siempre será útil y bienvenido en esta comunidad.</p>\n\n\n\n<p>Y, sinceramente, creo que en esta quinta <strong>WordCamp</strong>, la organización de Pontevedra va a lograr que este <strong>evento de WordPress</strong> aumente de forma considerable la familia “WordPressera” pues, con el planteamiento de este año, han conseguido superarse con creces.</p>\n\n\n\n<p>Así que, ¿a qué esperas?&#8230;&nbsp;</p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Aún no has comprado tu entrada?&#8230;</h2>\n\n\n\n<p>Pues pásate por <a href=\"https://pontevedra.wordcamp.org/2024/es/entradas/\">este enlace</a> y no pierdas la oportunidad de asistir a esta vuelta al (cole) <strong>WordCamp</strong> para aprender sobre el emprendimiento, volver a encontrarte con tus compañeros de clase y conocer a unos cuantos nuevos que no te esperabas.</p>\n\n\n\n<p>Así que prepárate y ponte guapo, ponte guapa y&#8230;</p>\n\n\n\n<p>¡PonteWordCamp, Pontevedra!</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:93:\"https://es.wordpress.org/2024/09/13/vuelta-al-cole-wordcamp-2024-ponte-guapa-pontevedra/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"655334\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:82:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:51:\"WordPress 6.6.2 – Actualización de mantenimiento\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://es.wordpress.org/2024/09/10/wordpress-6-6-2-actualizacion-de-mantenimiento/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:92:\"https://es.wordpress.org/2024/09/10/wordpress-6-6-2-actualizacion-de-mantenimiento/#comments\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 10 Sep 2024 17:24:38 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:4:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:13:\"Mantenimiento\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:3:\"6.6\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:5:\"6.6.2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=655336\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:400:\"¡Ya está disponible WordPress 6.6.2! Esta versión menor incluye 15 correcciones a fallos en el núcleo y 11 en el editor de bloques, solucionando problemas como cambios específicos de CSS inesperado en ciertos temas. Para ver un resumen completo de las actualizaciones de mantenimiento puedes revsiar el anuncio de la versión candidata a definitiva (en inglés). WordPress 6.6.2 es [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:8402:\"\n<h2 class=\"wp-block-heading\">¡Ya está disponible WordPress 6.6.2!</h2>\n\n\n\n<p>Esta versión menor incluye <a href=\"https://core.trac.wordpress.org/query?status=closed&amp;id=!61982&amp;milestone=6.6.2&amp;group=status&amp;col=id&amp;col=summary&amp;col=owner&amp;col=type&amp;col=priority&amp;col=component&amp;col=version&amp;col=keywords&amp;order=id\">15 correcciones a fallos en el núcleo</a> y <a href=\"https://core.trac.wordpress.org/ticket/61982#comment:5\">11 en el editor de bloques</a>, solucionando problemas como cambios específicos de CSS inesperado en ciertos temas. Para ver un resumen completo de las actualizaciones de mantenimiento puedes revsiar el <a href=\"https://make.wordpress.org/core/2024/09/04/wordpress-6-6-2-rc1-is-now-available/\">anuncio de la versión candidata a definitiva (en inglés)</a>.</p>\n\n\n\n<p>WordPress 6.6.2 es una actualización de ciclo corto. La siguiente actualización mayor será la <a href=\"https://make.wordpress.org/core/6-7/\">versión 6.7</a>, planificada para el 12 de noviembre de 2024.</p>\n\n\n\n<p>Si tienes sitios compatibles con las actualizaciones automáticas en segundo plano el proceso de actualización empezará automáticamente.</p>\n\n\n\n<p>Puedes <a href=\"https://wordpress.org/wordpress-6.6.2.zip\">descargar WordPress 6.6.2 desde WordPress.org</a>, o visitar el escritorio de tu WordPress, hacer clic en «Actualizaciones» y luego hacer clic en «Actualizar ahora».</p>\n\n\n\n<p>Para informarte más sobre esta actualización <a href=\"https://wordpress.org/support/wordpress-version/version-6-6-2\">visita el sitio del centro de ayuda</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Gracias a estos contribuidores a WordPress</h2>\n\n\n\n<p>Esta versión la dirigieron <a href=\"https://profiles.wordpress.org/hellofromTonya\">Tonya Mork</a> y <a href=\"https://profiles.wordpress.org/vcanales/\">Vicente Canales</a>, con la mentoría de <a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a>.</p>\n\n\n\n<p>WordPress 6.6.2 no habría sido posible sin las contribuciones de las siguientes personas. Su coordinación asíncrona a la hora de convertir correcciones de mantenimiento en una versión es table es la constatación del potencial y capacidad de la comunidad WordPress. </p>\n\n\n\n<p><a href=\"https://profiles.wordpress.org/jorbin\">Aaron Jorbin</a>,&nbsp;<a href=\"https://profiles.wordpress.org/aaronrobertshaw\">Aaron Robertshaw</a>,&nbsp;<a href=\"https://profiles.wordpress.org/adamsilverstein\">Adam Silverstein</a>,&nbsp;<a href=\"https://profiles.wordpress.org/wildworks\">Aki Hamano</a>,&nbsp;<a href=\"https://profiles.wordpress.org/atachibana\">Akira Tachibana</a>,&nbsp;<a href=\"https://profiles.wordpress.org/akshat2802\">Akshat Kakkad</a>,&nbsp;<a href=\"https://profiles.wordpress.org/harlet7\">Alexandru Horeanu</a>,&nbsp;<a href=\"https://profiles.wordpress.org/amitraj2203\">Amit Raj</a>,&nbsp;<a href=\"https://profiles.wordpress.org/andreiglingeanu\">andreiglingeanu</a>,&nbsp;<a href=\"https://profiles.wordpress.org/andrewserong\">Andrew Serong</a>,&nbsp;<a href=\"https://profiles.wordpress.org/the-ank\">Ankur Vishwakarma</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ahortin\">Anthony Hortin</a>,&nbsp;<a href=\"https://profiles.wordpress.org/apmeyer\">apmeyer</a>,&nbsp;<a href=\"https://profiles.wordpress.org/aristath\">Ari Stathopoulos</a>,&nbsp;<a href=\"https://profiles.wordpress.org/rainbowgeek\">Benjamin Denis</a>,&nbsp;<a href=\"https://profiles.wordpress.org/bernhard-reiter\">bernhard-reiter</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ironprogrammer\">Brian Alexander</a>,&nbsp;<a href=\"https://profiles.wordpress.org/freibergergarcia\">Bruno Freiberger Garcia</a>,&nbsp;<a href=\"https://profiles.wordpress.org/poena\">Carolina Nymark</a>,&nbsp;<a href=\"https://profiles.wordpress.org/costdev\">Colin Stewart</a>,&nbsp;<a href=\"https://profiles.wordpress.org/talldanwp\">Daniel Richards</a>,&nbsp;<a href=\"https://profiles.wordpress.org/dballari\">David Ballarin Prunera</a>,&nbsp;<a href=\"https://profiles.wordpress.org/davidbaumwald\">David Baumwald</a>,&nbsp;<a href=\"https://profiles.wordpress.org/dlh\">David Herrera</a>,&nbsp;<a href=\"https://profiles.wordpress.org/dsas\">Dean Sas</a>,&nbsp;<a href=\"https://profiles.wordpress.org/debarghyabanerjee\">DEBARGHYA BANERJEE</a>,&nbsp;<a href=\"https://profiles.wordpress.org/dmsnell\">Dennis Snell</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mamaduka\">George Mamadashvili</a>,&nbsp;<a href=\"https://profiles.wordpress.org/gziolo\">Greg Ziółkowski</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jamesros161\">James Rosado</a>,&nbsp;<a href=\"https://profiles.wordpress.org/madtownlems\">Jason LeMahieu (MadtownLems)</a>,&nbsp;<a href=\"https://profiles.wordpress.org/audrasjb\">Jb Audras</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jeherve\">Jeremy Herve</a>,&nbsp;<a href=\"https://profiles.wordpress.org/joedolson\">Joe Dolson</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jonsurrell\">Jon Surrell</a>,&nbsp;<a href=\"https://profiles.wordpress.org/josklever\">Jos Klever</a>,&nbsp;<a href=\"https://profiles.wordpress.org/karan4word\">karan4official</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ryelle\">Kelly Choyce-Dwan</a>,&nbsp;<a href=\"https://profiles.wordpress.org/kowsar89\">Kowsar Hossain</a>,&nbsp;<a href=\"https://profiles.wordpress.org/kracked888\">kracked888</a>,&nbsp;<a href=\"https://profiles.wordpress.org/luisherranz\">luisherranz</a>,&nbsp;<a href=\"https://profiles.wordpress.org/clorith\">Marius L. J.</a>,&nbsp;<a href=\"https://profiles.wordpress.org/marius84\">mariushosting</a>,&nbsp;<a href=\"https://profiles.wordpress.org/markhowellsmead\">Mark Howells-Mead</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mattraines\">mattraines</a>,&nbsp;<a href=\"https://profiles.wordpress.org/michaelwp85\">michaelwp85</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mukesh27\">Mukesh Panchal</a>,&nbsp;<a href=\"https://profiles.wordpress.org/munyagu\">munyagu</a>,&nbsp;<a href=\"https://profiles.wordpress.org/narenin\">Narendra Sishodiya</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ndiego\">Nick Diego</a>,&nbsp;<a href=\"https://profiles.wordpress.org/nithi22\">Nithin John</a>,&nbsp;<a href=\"https://profiles.wordpress.org/nithins53\">Nithin SreeRaj</a>,&nbsp;<a href=\"https://profiles.wordpress.org/alshakero\">Omar Alshaker</a>,&nbsp;<a href=\"https://profiles.wordpress.org/paaljoachim\">Paal Joachim Romdahl</a>,&nbsp;<a href=\"https://profiles.wordpress.org/pamprn\">Pamela Ribeiro</a>,&nbsp;<a href=\"https://profiles.wordpress.org/swissspidy\">Pascal Birchler</a>,&nbsp;<a href=\"https://profiles.wordpress.org/pbiron\">Paul Biron</a>,&nbsp;<a href=\"https://profiles.wordpress.org/peterwilsoncc\">Peter Wilson</a>,&nbsp;<a href=\"https://profiles.wordpress.org/presstoke\">presstoke</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ramonopoly\">ramonopoly</a>,&nbsp;<a href=\"https://profiles.wordpress.org/youknowriad\">Riad Benguella</a>,&nbsp;<a href=\"https://profiles.wordpress.org/coffee2code\">Scott Reilly</a>,&nbsp;<a href=\"https://profiles.wordpress.org/sergeybiryukov\">Sergey Biryukov</a>,&nbsp;<a href=\"https://profiles.wordpress.org/shailu25\">Shail Mehta</a>,&nbsp;<a href=\"https://profiles.wordpress.org/smerriman\">smerriman</a>,&nbsp;<a href=\"https://profiles.wordpress.org/sabernhardt\">Stephen Bernhardt</a>,&nbsp;<a href=\"https://profiles.wordpress.org/hellofromTonya\">Tonya Mork</a>,&nbsp;<a href=\"https://profiles.wordpress.org/vcanales\">Vicente Canales</a>,&nbsp;<a href=\"https://profiles.wordpress.org/wongjn\">wongjn</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ytfeldrawkcab\">ytfeLdrawkcaB</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Cómo contribuir</h2>\n\n\n\n<p>Para involucrarte en el desarrollo del núcleo de WordPress pásate por el Trac, <a href=\"https://core.trac.wordpress.org/report/6\">elige un tique</a> y únete a la conversación en los canales <a href=\"https://wordpress.slack.com/archives/C02RQBWTW\">#core</a> y <a href=\"https://wordpress.slack.com/archives/C07BTF54N68\">#6-7-release-leads</a>. ¿Necesitas ayuda? Revisa el <a href=\"https://make.wordpress.org/core/handbook/\">manual de contribuidor al núcleo</a>.</p>\n\n\n\n<p>Como recordatorio, ve <a href=\"https://wordpress.org/https://make.wordpress.org/plugins/2024/09/04/upcoming-security-changes-for-plugin-and-theme-authors-on-wordpress-org/\">esta entrada para conocer los próximos cambios de seguridad para autores de plugins y temas de WordPress.org</a>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"https://es.wordpress.org/2024/09/10/wordpress-6-6-2-actualizacion-de-mantenimiento/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"655336\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:46:\"Meetup de septiembre 2024 y próximas WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"https://es.wordpress.org/2024/09/10/meetups-y-wordcamps/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"https://es.wordpress.org/2024/09/10/meetups-y-wordcamps/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 10 Sep 2024 10:59:46 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:6:\"Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=627801\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:347:\"En la comunidad de WordPress nos gusta el contacto, vernos las caritas y conocer a otros frikis como nosotros dispuestos a colaborar y, sobre todo, a estar un buen rato charlando sobre temas varios, generalmente relacionados con WordPress. ¿Cómo lo hacemos? A través de las Meetups y de las WordCamps. Encuentra las próximas en este artículo.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Cris Quintero\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:9443:\"\n<p>Si llevas por aquí un tiempito, ya conoces el funcionamiento y puedes <a href=\"#meetups_mesuales\" data-type=\"internal\" data-id=\"#meetups_mesuales\">ir directamente a la tabla de Meetup de este mes</a>.</p>\n\n\n\n<p>Si acabas de llegar, una de las primeras cosas que debes de saber es que en la comunidad de WordPress nos gusta el contacto, vernos las caritas y conocer a otros frikis como nosotros dispuestos a colaborar y, sobre todo, a estar un buen rato charlando sobre temas varios, generalmente relacionados con WordPress, pero no siempre, o no obligatoriamente.</p>\n\n\n\n<p>En WordPress, además de organizarnos para llevar a cabo mejoras de la herramienta y de la comunidad, nos reunimos siempre que podemos de forma presencial (que es donde está “la chicha”, cuando nos lo pasamos piruleta). ¿Cómo lo hacemos? A través de las Meetup y de las WordCamp.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Meetup</h2>\n\n\n\n<p>Las Meetup son, pues eso, reuniones que se organizan en diferentes pueblos y ciudades, en las que normalmente acude algún ponente imponente a dar una charla sobre algún tema de interés (emprendimiento, marketing, ventas, programación, tendencias online…), todo bajo el paraguas de WordPress.</p>\n\n\n\n<p>Cada meetup es independiente y tiene un sistema de organización propio, en función de la cantidad de miembros y de su disponibilidad y ganas de marcha.</p>\n\n\n\n<p>Lo habitual es que las Meetup se realicen una vez al mes. Entra <a href=\"https://events.wordpress.org/\" target=\"_blank\" rel=\"noreferrer noopener\">aquí</a> y busca el nombre de tu ciudad o comunidad para descubrir cuál es tu Meetup más cercana y apúntate para recibir notificaciones de sus próximas reuniones.</p>\n\n\n\n<p>Puedes hacerte miembro y participar en todas las Meetup que quieras, aquí no hay límite, incluso apuntarte a algunas de otros países si eres de esos que tiene FOMO y no quieren perderse nada.</p>\n\n\n\n<p>Lo importante es que te apuntes. Ya verás que antes de que te des cuenta estarás implicado hasta las cejas conociendo a un montón de gente más maja que las pesetas* <em>(antigua moneda española que dejó de estar vigente el siglo pasado)</em>.</p>\n\n\n\n<p>Para simplificarte el trabajo y dejártelo todo masticadito, aquí te dejamos el listado de las Meetup programadas para este mes.</p>\n\n\n\n<p>Pincha en la que más te llame la atención y apúntate si quieres formar parte de esta nuestra comunidad (y la de todos). Y si no hay Meetup en tu ciudad, deberías plantearte montarla tú mismo. <a href=\"https://es.wordpress.org/team/handbook/comunidad/meetup/aprobacion/\" target=\"_blank\" rel=\"noreferrer noopener\">Aquí</a> tienes toda la info para hacerlo.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"meetups_mesuales\">Meetup en España en septiembre de 2024</h3>\n\n\n\n<figure class=\"wp-block-table\"><table><thead><tr><th><strong>Fecha</strong></th><th><strong>Ciudad</strong></th><th><strong>Título del evento</strong></th></tr></thead><tbody><tr><td>10/09/2024</td><td>Terrassa</td><td><a href=\"https://www.meetup.com/terrassa-wordpress-meetup/events/303195155\" target=\"_blank\" rel=\"noreferrer noopener\">Aprovecha al máximo las últimas novedades de WordPress</a></td></tr><tr><td>11/09/2024</td><td>Granada</td><td><a href=\"https://www.meetup.com/granada-wordpress-meetup/events/302977374\" target=\"_blank\" rel=\"noreferrer noopener\">Habilidades de la oratoria y la comunicación para conectar con la audiencia</a></td></tr><tr><td>12/09/2024</td><td>Madrid</td><td><a href=\"https://www.meetup.com/wordpress-madrid/events/303091820\" target=\"_blank\" rel=\"noreferrer noopener\">Gatos y Hackers: Cómo nos atacan los malos y cómo podemos defendernos</a></td></tr><tr><td>12/09/2024</td><td>Valladolid</td><td><a href=\"https://www.meetup.com/valladolid-wordpress-meetup/events/303229772\" target=\"_blank\" rel=\"noreferrer noopener\">Taller web y blogs en 2024. Selección de plugins para WordPress.</a></td></tr><tr><td>12/09/2024</td><td>Tarragona</td><td><a href=\"https://www.meetup.com/wordpresstarragona/events/303175353\" target=\"_blank\" rel=\"noreferrer noopener\">WordPress &amp; Beers – Septiembre</a></td></tr><tr><td>12/09/2024</td><td>Alicante</td><td><a href=\"https://www.meetup.com/wordpress-alicante/events/303112083\" target=\"_blank\" rel=\"noreferrer noopener\">El paso a paso de un plan de acción que sí cumplas con Meritxell Mayans</a></td></tr><tr><td>12/09/2024</td><td>Las Palmas de Gran Canaria</td><td><a href=\"https://www.meetup.com/wordpress-las-palmas-de-gran-canaria/events/302275776\" target=\"_blank\" rel=\"noreferrer noopener\">¿Qué contenido debo crear?</a></td></tr><tr><td>18/09/2024</td><td>Alcalá de Henares</td><td><a href=\"https://www.meetup.com/alcala-de-henares-wordpress-meetup-group/events/303255437\" target=\"_blank\" rel=\"noreferrer noopener\">SEO para lanzamientos</a></td></tr><tr><td>18/09/2024</td><td>Santiago de Compostela</td><td><a href=\"https://www.meetup.com/santiago-de-compostela-wordpress-meetup-group/events/303253497\" target=\"_blank\" rel=\"noreferrer noopener\">Claves para emprender con el Desarrollo de Software</a></td></tr><tr><td>19/09/2024</td><td>A Coruña</td><td><a href=\"https://www.meetup.com/wordpresscoruna/events/303256783\" target=\"_blank\" rel=\"noreferrer noopener\">El arte de medir en WordPress</a></td></tr><tr><td>20/09/2024</td><td>Igualada</td><td><a href=\"https://www.meetup.com/igualada-wordpress-meetup/events/302547446\" target=\"_blank\" rel=\"noreferrer noopener\">Descubre Surecart: ¿La Mejor Alternativa a WooCommerce?</a></td></tr><tr><td>20/09/2024</td><td>Denia </td><td><a href=\"https://www.meetup.com/es-ES/wordpress-denia/events/301872268/\" target=\"_blank\" rel=\"noreferrer noopener\">Empezando WP #4: Recopilación de sesiones anteriores + Creación de contenidos</a> (<img src=\"https://s.w.org/images/core/emoji/15.0.3/72x72/1f310.png\" alt=\"🌐\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" />Evento online)</td></tr><tr><td>25/09/2024</td><td>Sevilla</td><td><a href=\"https://www.meetup.com/wordpress-sevilla/events/303231031\" target=\"_blank\" rel=\"noreferrer noopener\">Planes para el nuevo curso</a></td></tr><tr><td>26/09/2024</td><td>Griñón</td><td><a href=\"https://www.meetup.com/wordpress-grinon/events/303261304\" target=\"_blank\" rel=\"noreferrer noopener\">Comienzo de Temporada: Planifica y Participa en Nuestra Meetup de Griñón</a></td></tr><tr><td>26/09/2024</td><td>Oviedo</td><td><a href=\"https://www.meetup.com/wordpress-oviedo/events/302267852\" target=\"_blank\" rel=\"noreferrer noopener\">Bienvenida a Oviedo WordPress</a></td></tr><tr><td>27/09/2024</td><td>Benidorm</td><td><a href=\"https://www.meetup.com/wordpress-benidorm/events/303486163/?eventOrigin=group_upcoming_events\">Como Impulsar Proyectos Web con los Recursos Gratuitos de la Comunidad WordPress</a></td></tr></tbody></table></figure>\n\n\n\n<p>Y, como lo de las reuniones mensuales nos parecía poco, también tenemos las WordCamp. Esto ya son palabras mayores…</p>\n\n\n\n<h2 class=\"wp-block-heading\">WordCamp y Eventos</h2>\n\n\n\n<p>Las WordCamp son eventos más <em>tochos</em>, más elaborados y más completos que el baño de un after (pero con más higiene).</p>\n\n\n\n<p>Las WordCamp se celebran una vez al año, duran dos o tres días y suelen tener varios ponentes referentes en su sector y otras actividades para fomentar la participación en la comunidad WordPress y hacer networking.</p>\n\n\n\n<p>Las WordCamp también se organizan de forma independiente. No todas las ciudades con Meetup organizan WordCamp (sería un poco locura) pero sí que todas las WordCamp tienen su propia Meetup, por eso de no perder el contacto a lo largo del año.</p>\n\n\n\n<h3 class=\"wp-block-heading\">WordCamp y eventos que se vislumbran en el horizonte</h3>\n\n\n\n<figure class=\"wp-block-table\"><table><thead><tr><th><strong>Fecha</strong></th><th><strong>Ciudad</strong></th><th><strong>Título del evento</strong></th></tr></thead><tbody><tr><td>20-22 de septiembre de 2024</td><td>Pontevedra</td><td><a href=\"https://pontevedra.wordcamp.org/2024/\" target=\"_blank\" rel=\"noreferrer noopener\">WordCamp Pontevedra sobre emprendimiento</a></td></tr><tr><td>28 de septiembre de 2024</td><td>Valencia</td><td><a href=\"https://events.wordpress.org/valencia/2024/diversityday/\" target=\"_blank\" rel=\"noreferrer noopener\">WordPress Diversity Day Valencia</a></td></tr><tr><td>19 de octubre de 2024</td><td>Denia</td><td><a href=\"https://events.wordpress.org/denia/2024/trabajoremoto/\" target=\"_blank\" rel=\"noreferrer noopener\">Trabajo remoto:<br>transformando el futuro<br>con WordPress</a> (<img src=\"https://s.w.org/images/core/emoji/15.0.3/72x72/1f310.png\" alt=\"🌐\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" />Evento online)</td></tr><tr><td>26 y 27 de octubre de 2024</td><td>Granada</td><td><a href=\"https://granada.wordcamp.org/2024/\" target=\"_blank\" rel=\"noreferrer noopener\">WordCamp Granada</a></td></tr></tbody></table></figure>\n\n\n\n<p>Ya te lo hemos dicho, somos una comunidad muy activa, nos gusta vernos a menudo y, sobre todo, si hay unas cañitas de por medio.</p>\n\n\n\n<p>Pero lo que más nos motiva es que se vaya uniendo gente nueva. Aquí hay espacio para todo aquel que quiera aportar su granito de arena o simplemente conocer a gente currante, divertida y un poco tocada de la cabeza (pues como tú).</p>\n\n\n\n<p>Así que…, ya sabes, toca el timbre de la comunidad WordPress, que te abrimos. </p>\n\n\n\n<p><strong>¡Nos vemos en la próxima quedada!</strong></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:61:\"https://es.wordpress.org/2024/09/10/meetups-y-wordcamps/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"627801\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:50:\"Contribuimos juntos para avanzar el Spain Handbook\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:87:\"https://es.wordpress.org/2024/09/05/contribuimos-juntos-para-avanzar-el-spain-handbook/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:95:\"https://es.wordpress.org/2024/09/05/contribuimos-juntos-para-avanzar-el-spain-handbook/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 05 Sep 2024 12:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"Comunidad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=655292\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:185:\"¿Quieres colaborar en la comunidad de WordPress?\nEl equipo de documentación hará contributors, trabajo en equipo, para ayudar a crear y organizar los nuevos manuales.\n¡Te esperamos!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Jesus Yesares\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:4929:\"\n<p>No sé si estás al tanto de la movida, pero hace no demasiado tiempo ha visto la luz un nuevo equipo en ​​España: el equipo de documentación.</p>\n\n\n\n<p>Y digo que ha visto la luz, porque durante un buen tiempo, un grupúsculo de inconformistas del equipo de marketing estuvieron trabajando en la sombra, germinando la semilla de lo que hoy fundamenta el trabajo de este nuevo equipo. Este grupo de colaboradores estuvo trabajando en modo “proyecto piloto” lejos del mundanal ruido para poder dar forma a un método de trabajo que fuese eficiente, adaptando el modus operandi del equipo de documentación global, al equipo de documentación de la comunidad de WordPress España.</p>\n\n\n\n<p>Finalmente, hace unos meses, <a href=\"https://es.wordpress.org/team/2024/04/23/equipo-de-documentacion-de-wordpress-espana-y-sus-grupos-de-trabajo-en-2024/\">se presentó este nuevo equipo y sus grupos de trabajo formalmente en este artículo</a>.</p>\n\n\n\n<p>Uno de estos grupos de trabajo, que fue la semilla del actual equipo de documentación, fueron los que sentaron las bases técnicas y metodológicas del trabajo que se está haciendo actualmente, centrándose en el Spain Handbook. ¿Qué es esto?</p>\n\n\n\n<p>Los manuales o el Spain handbook, son básicamente lo que vas a encontrar en el menú de WordPress España, que se encuentra en Colabora <span aria-hidden=\"true\" class=\"wp-exclude-emoji\">→</span> <a href=\"https://es.wordpress.org/team/handbook/\">Manuales</a>, es decir, los manuales que todo colaborador de WordPress España debería tener como referencia, da igual el equipo en el que colabore.</p>\n\n\n\n<p></p>\n\n\n\n<figure class=\"wp-block-image\"><img loading=\"lazy\" decoding=\"async\" width=\"1600\" height=\"394\" src=\"https://es.wordpress.org/files/2024/09/image.png\" alt=\"\" class=\"wp-image-655299\" srcset=\"https://es.wordpress.org/files/2024/09/image.png 1600w, https://es.wordpress.org/files/2024/09/image-300x74.png 300w, https://es.wordpress.org/files/2024/09/image-1024x252.png 1024w, https://es.wordpress.org/files/2024/09/image-768x189.png 768w, https://es.wordpress.org/files/2024/09/image-1536x378.png 1536w\" sizes=\"auto, (max-width: 1600px) 100vw, 1600px\" /></figure>\n\n\n\n<p></p>\n\n\n\n<p>Ahora que ya sabes de lo que te estoy hablando, creo que te va a interesar lo que te voy&nbsp; a contar a continuación.</p>\n\n\n\n<p>Este grupo de trabajo, ha estado sacando adelante muchas tareas que había pendientes, sentando las bases y creando una estructura práctica y de fácil manejo para que el resto de equipos pudieran añadir su contenido a esta sección de la web de WordPress España.</p>\n\n\n\n<p>Pero ahora necesitamos más manos. Necesitamos que tú, colaborador en cualquiera de los equipos de trabajo, o tú, que eres responsable de equipo (especialmente tú), nos eches una mano, y vuelques ahí en la sección que hemos preparado para tu equipo todo el conocimiento que aplicáis a lo largo del tiempo en vuestro trabajo, que ayuda a que la comunidad de WordPress España sea una de las más fuertes del mundo (y esto no es una opinión, lo avalan los datos).</p>\n\n\n\n<p>Por eso, desde el equipo de documentación de España hemos decidido llevar a cabo una nueva propuesta. Siguiendo los pasos del equipo global de documentación, pensamos que puede ser una buena idea hacer un contributor online público, con una periodicidad mensual.</p>\n\n\n\n<p>Esto permitirá, al principio, que cualquier colaborador pueda resolver sus dudas, desbloquear tareas y hacer propuestas. Asimismo, queremos que sirva también para que los diferentes responsables de equipo se acerquen para dar un empujón a aquellos capítulos del manual que les corresponde.</p>\n\n\n\n<h2 class=\"wp-block-heading\">¿En qué trabajaremos?</h2>\n\n\n\n<p>Todas tareas que hay pendientes de hacer, se encuentran en los <a href=\"https://github.com/orgs/WordPress/projects/159/views/1\">proyectos publicados en el repositorio de GitHub del Spain handbook</a>.</p>\n\n\n\n<p>Todos los martes, a las 17:30, mantenemos una reunión los dos grupos de trabajo para ponernos al día de lo que se está haciendo (salvo este pequeño parón veraniego).</p>\n\n\n\n<p>A diferencia de dicha reunión, lo que estamos proponiendo nosotros se trata de un contributor en toda regla, es decir, un tiempo para trabajar juntos y desbloquear “cosas”.</p>\n\n\n\n<p>Si tienes alguna propuesta o duda, estaremos encantados de escucharte en los comentarios.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Me muero de ganas de trabajar, ¿cuándo nos vemos?</h2>\n\n\n\n<p>Por cierto, todavía no hemos puesto fecha, pero una primera propuesta sería el tercer jueves de cada mes a las 17:30, con una duración de 2 horas (máximo 3 horas).</p>\n\n\n\n<p>Pero esperamos tus sugerencias en los comentarios de este artículo.</p>\n\n\n\n<p></p>\n\n\n\n<p>Co-redacción: <a href=\'https://profiles.wordpress.org/josepmoran/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>josepmoran</a></p>\n\n\n\n<p></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:92:\"https://es.wordpress.org/2024/09/05/contribuimos-juntos-para-avanzar-el-spain-handbook/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"655292\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"¿Qué hace que la comunidad de WordPress sea tan especial?\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:92:\"https://es.wordpress.org/2024/08/29/que-hace-que-la-comunidad-de-wordpress-sea-tan-especial/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:100:\"https://es.wordpress.org/2024/08/29/que-hace-que-la-comunidad-de-wordpress-sea-tan-especial/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 29 Aug 2024 07:50:02 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"Comunidad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=653482\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:340:\"Imagina formar parte de un ecosistema donde la colaboración, el conocimiento compartido y la innovación son el pan de cada día. ¿Qué pasaría si pudieras conectarte con personas de todo el mundo que comparten tus mismos intereses, valores y pasión por la web? Si eres un entusiasta de WordPress, ¡esto ya es una realidad! Y [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Alvaro Torres\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:2714:\"\n<p>Imagina formar parte de un ecosistema donde la colaboración, el conocimiento compartido y la innovación son el pan de cada día.</p>\n\n\n\n<p>¿Qué pasaría si pudieras conectarte con personas de todo el mundo que comparten tus mismos intereses, valores y pasión por la web?</p>\n\n\n\n<p>Si eres un entusiasta de WordPress, ¡esto ya es una realidad! Y si aún no lo eres, tenemos algo muy especial para ti.</p>\n\n\n\n<p>El próximo lunes, <strong>Alex Ruiz, una conocida figura de la comunidad de WordPress</strong>, nos hablará de los secretos que hacen de esta comunidad un lugar tan especial.</p>\n\n\n\n<p>Desde los eventos llenos de creatividad hasta las conexiones profundas que se forjan entre sus miembros, Alex revelará los ingredientes que hacen única a esta comunidad global.</p>\n\n\n\n<p>¿Por qué WordPress ha logrado reunir a millones de personas en todo el mundo? ¿Qué hace que desarrolladores, diseñadores, bloggers, marketers y hasta principiantes se sientan tan bienvenidos y motivados a contribuir? Alex Ruiz tiene las respuestas.</p>\n\n\n\n<p>¿Quién sabe? Podrías estar a un clic de distancia de tu próxima gran oportunidad o de conocer a un colaborador clave para tu próximo proyecto.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://es.wordpress.org/files/2024/06/Horario-Quedadas.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"573\" src=\"https://es.wordpress.org/files/2024/06/Horario-Quedadas-1024x573.png\" alt=\"Horario de quedadas WordPress en español\" class=\"wp-image-590261\" srcset=\"https://es.wordpress.org/files/2024/06/Horario-Quedadas-1024x573.png 1024w, https://es.wordpress.org/files/2024/06/Horario-Quedadas-300x168.png 300w, https://es.wordpress.org/files/2024/06/Horario-Quedadas-768x430.png 768w, https://es.wordpress.org/files/2024/06/Horario-Quedadas-1536x859.png 1536w, https://es.wordpress.org/files/2024/06/Horario-Quedadas.png 1890w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué es Quedadas WordPress en Español?</h2>\n\n\n\n<p>Quedadas Online el 1er. Lunes de cada mes a las 20:00 (de España), dirigidas fundamentalmente a la Comunidad de habla hispana (España y Latinoamérica).</p>\n\n\n\n<p>Charlaremos de temas específicos, de una manera informal, o un Ponente nos introducirá en una cuestión relacionada con WordPress, para posteriormente hacer networking entre todos.</p>\n\n\n\n<p>Repasaremos también las próximas meetups y WordCamps, a ver si tienes alguna cerca. Así que si quieres charlar un rato, echar unas risas y conocer personas de la Comunidad WordPress de otros lugares, sólo tienes que apuntarte, y entrar en la Sala de Zoom el día y hora correspondiente.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:97:\"https://es.wordpress.org/2024/08/29/que-hace-que-la-comunidad-de-wordpress-sea-tan-especial/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"653482\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:82:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:51:\"WordPress 6.6.1 – Actualización de mantenimiento\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://es.wordpress.org/2024/07/23/wordpress-6-6-1-actualizacion-de-mantenimiento/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:91:\"https://es.wordpress.org/2024/07/23/wordpress-6-6-1-actualizacion-de-mantenimiento/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 23 Jul 2024 16:31:17 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:4:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:13:\"Mantenimiento\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:3:\"6.6\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:5:\"6.6.1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=649724\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:405:\"¡Ya está disponible WordPress 6.6.1! Esta actualización menor incluye 7 correcciones a fallos en el núcleo y 9 correcciones de fallos en el editor de bloques. Puedes revisar un resumen de las actualizaciones de mantenimiento de esta versión leyendo el anuncio de la versión candidada a definitiva. WordPress 6.6.1 es una actualización de ciclo corto. La siguiente actualización mayor [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6798:\"\n<p><strong>¡Ya está disponible WordPress 6.6.1!</strong></p>\n\n\n\n<p>Esta actualización menor incluye <a href=\"https://core.trac.wordpress.org/query?status=closed&amp;id=!61692&amp;milestone=6.6.1&amp;group=status&amp;col=id&amp;col=summary&amp;col=owner&amp;col=type&amp;col=priority&amp;col=component&amp;col=version&amp;col=keywords&amp;order=priority\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">7 correcciones a fallos en el núcleo</a> y <a href=\"https://core.trac.wordpress.org/ticket/61692#comment:4\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">9 correcciones de fallos en el editor de bloques</a>. Puedes revisar un resumen de las actualizaciones de mantenimiento de esta versión leyendo el <a href=\"https://make.wordpress.org/core/2024/07/18/wordpress-6-6-1-rc1-is-now-available/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">anuncio de la versión candidada a definitiva</a>.</p>\n\n\n\n<p>WordPress 6.6.1 es una actualización de ciclo corto. La siguiente actualización mayor será la <a href=\"https://make.wordpress.org/core/6-7/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">versión 6.7</a>, planificada para noviembre de 2024.</p>\n\n\n\n<p>Si tienes sitios con la actualizaciones automáticas en segundo plano activas el proceso de actualización empezará automáticamente.</p>\n\n\n\n<p>Puedes <a href=\"https://es.wordpress.org/latest-es_ES.zip\" rel=\"nofollow\">descargar WordPress 6.6.1 desde WordPress.org</a>, o visitar tu escritorio de WordPress, hacer clic en «Actualizaciones» y luego hacer clic en «Actualizar ahora».</p>\n\n\n\n<p>Para más información sobre esta actualización <a href=\"https://wordpress.org/support/wordpress-version/version-6-6-1\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">visita el centro de ayuda</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Gracias a estos colaboradores de WordPress</h2>\n\n\n\n<p>Esta versión la <a href=\"https://profiles.wordpress.org/hellofromTonya\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Tonya Mork</a> y <a href=\"https://profiles.wordpress.org/ellatrix/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Ella</a>.</p>\n\n\n\n<p>WordPress 6.6.1 no habría sido posible sin las contribuciones de las siguientes personas. Su coordinación asíncrona a la hora de entregar las correcciones de mantenimiento y convertirlas en una versión estable es una declaración del potencial y la capacidad de la comunidad WordPress.</p>\n\n\n\n<p><a href=\"https://profiles.wordpress.org/jorbin%22\">Aaron Jorbin</a>,&nbsp;<a href=\"https://profiles.wordpress.org/aaronrobertshaw\">Aaron Robertshaw</a>,&nbsp;<a href=\"https://profiles.wordpress.org/wildworks\">Aki Hamano</a>,&nbsp;<a href=\"https://profiles.wordpress.org/amitraj2203\">Amit Raj</a>,&nbsp;<a href=\"https://profiles.wordpress.org/atachibana/\">Akira Tachibana</a>,&nbsp;<a href=\"https://profiles.wordpress.org/afercia\">Andrea Fercia</a>,&nbsp;<a href=\"https://profiles.wordpress.org/andrewserong\">Andrew Serong</a>,&nbsp;<a href=\"https://profiles.wordpress.org/annezazu\">annezazu</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ambrosiawt\">Art Smith</a>,&nbsp;<a href=\"https://profiles.wordpress.org/bgardner\">Brian Gardner</a>,&nbsp;<a href=\"https://profiles.wordpress.org/poena\">Carolina Nymark</a>,&nbsp;<a href=\"https://profiles.wordpress.org/cbirdsong\">cbirdsong</a>,&nbsp;<a href=\"https://profiles.wordpress.org/butterflymedia\">Ciprian</a>,&nbsp;<a href=\"https://profiles.wordpress.org/clarktbt\">Clark</a>,&nbsp;<a href=\"https://profiles.wordpress.org/courane01\">Courtney Robertson</a>,&nbsp;<a href=\"https://profiles.wordpress.org/talldanwp\">Daniel Richards</a>,&nbsp;<a href=\"https://profiles.wordpress.org/davidbaumwald\">David Baumwald</a>,&nbsp;<a href=\"https://profiles.wordpress.org/dmsnell\">Dennis Snell</a>,&nbsp;<a href=\"https://profiles.wordpress.org/dd32\">Dion Hulse</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ellatrix\">Ella</a>,&nbsp;<a href=\"https://profiles.wordpress.org/annubis\">Eric-Oliver Mächler</a>,&nbsp;<a href=\"https://profiles.wordpress.org/fabiankaegy\">Fabian Kägy</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mamaduka\">George Mamadashvili</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jsnajdr\">Jarda Snajdr</a>,&nbsp;<a href=\"https://profiles.wordpress.org/audrasjb\">Jb Audras</a>,&nbsp;<a href=\"https://profiles.wordpress.org/joedolson\">Joe Dolson</a>,&nbsp;<a href=\"https://profiles.wordpress.org/joen\">Joen A.</a>,&nbsp;<a href=\"https://profiles.wordpress.org/jonsurrell\">Jon Surrell</a>,&nbsp;<a href=\"https://profiles.wordpress.org/laurelfulford/\">laurelfulford</a><a>,&nbsp;</a><a href=\"https://profiles.wordpress.org/mciampini\">Marco Ciampini</a>,&nbsp;<a href=\"https://profiles.wordpress.org/santosguillamot\">Mario Santos</a>,&nbsp;<a href=\"https://profiles.wordpress.org/markhowellsmead\">Mark Howells-Mead</a>,&nbsp;<a href=\"https://profiles.wordpress.org/mukesh27%20\">Mukesh Panchal</a>,&nbsp;<a href=\"https://profiles.wordpress.org/neotrope\">neotrope</a>,&nbsp;<a href=\"https://profiles.wordpress.org/swissspidy\">Pascal Birchler</a>,&nbsp;<a href=\"https://profiles.wordpress.org/pbiron\">Paul Biron</a>,&nbsp;<a href=\"https://profiles.wordpress.org/ramonopoly\">ramonopoly</a>,&nbsp;<a href=\"https://profiles.wordpress.org/raquelandefeld\">Raquel</a>,&nbsp;<a href=\"https://profiles.wordpress.org/youknowriad\">Riad Benguella</a>,&nbsp;<a href=\"https://profiles.wordpress.org/richtabor\">Rich Tabor</a>,&nbsp;<a href=\"https://profiles.wordpress.org/noisysocks\">Robert Anderson</a>,&nbsp;<a href=\"https://profiles.wordpress.org/SergeyBiryukov\">Sergey Biryukov</a>,&nbsp;<a href=\"https://profiles.wordpress.org/coffee2code/\">Scott Reilly</a>,&nbsp;<a href=\"https://profiles.wordpress.org/sourav08\">Sourav Pahwa</a>,&nbsp;<a href=\"https://profiles.wordpress.org/sabernhardt\">Stephen Bernhardt</a>,&nbsp;<a href=\"https://profiles.wordpress.org/sunil25393\">SunilPrajapati</a>,&nbsp;<a href=\"https://profiles.wordpress.org/hellofromTonya\">Tonya Mork</a>,&nbsp;<a href=\"https://profiles.wordpress.org/up1512001\">up1512001</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Cómo colaborar</h2>\n\n\n\n<p>Para participar en el desarrollo del núcleo de WordPress, ve al Trac, <a href=\"https://core.trac.wordpress.org/report/6\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">elige un tique</a> y únete a la conversación en los canales <a href=\"https://wordpress.slack.com/archives/C02RQBWTW\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">#core</a> y <a href=\"https://wordpress.slack.com/archives/C07BTF54N68\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">#6-7-release-leads</a>. ¿Necesitas ayuda? Consulta el <a href=\"https://make.wordpress.org/core/handbook/tutorials/faq-for-new-contributors/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">manual del colaborador del núcleo</a>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"https://es.wordpress.org/2024/07/23/wordpress-6-6-1-actualizacion-de-mantenimiento/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"649724\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\